import json
import boto3
import time
import logging
from typing import Dict, Any, Callable, List, Optional
from datetime import datetime
from botocore.exceptions import ClientError

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.message_handlers: Dict[str, Callable] = {}
        self.running = False
        
    def register_handler(self, message_type: str, handler: Callable):
        self.message_handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
        
    def poll_messages(self) -> List[Dict[str, Any]]:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            return response.get('Messages', [])
        except ClientError as e:
            logger.error(f"Error polling messages: {e}")
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Dict[str, Any]:
        try:
            body = json.loads(message['Body'])
            return {
                'message_id': message['MessageId'],
                'receipt_handle': message['ReceiptHandle'],
                'body': body,
                'message_type': body.get('type', 'unknown'),
                'payload': body.get('payload', {}),
                'attributes': message.get('Attributes', {}),
                'message_attributes': message.get('MessageAttributes', {})
            }
        except json.JSONDecodeError as e:
            logger.error(f"Error parsing message body: {e}")
            return {
                'message_id': message.get('MessageId', 'unknown'),
                'receipt_handle': message['ReceiptHandle'],
                'body': message['Body'],
                'message_type': 'invalid',
                'payload': {},
                'error': str(e)
            }
    
    def process_message(self, parsed_message: Dict[str, Any]) -> bool:
        message_type = parsed_message['message_type']
        
        if message_type == 'invalid':
            logger.error(f"Invalid message format: {parsed_message.get('error')}")
            return False
        
        handler = self.message_handlers.get(message_type)
        
        if handler is None:
            default_handler = self.message_handlers.get('default')
            if default_handler:
                handler = default_handler
            else:
                logger.warning(f"No handler found for message type: {message_type}")
                return False
        
        try:
            logger.info(f"Processing message type: {message_type}, ID: {parsed_message['message_id']}")
            result = handler(parsed_message)
            logger.info(f"Successfully processed message: {parsed_message['message_id']}")
            return result if isinstance(result, bool) else True
        except Exception as e:
            logger.error(f"Error processing message {parsed_message['message_id']}: {e}")
            return False
    
    def delete_message(self, receipt_handle: str) -> bool:
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info(f"Deleted message from queue")
            return True
        except ClientError as e:
            logger.error(f"Error deleting message: {e}")
            return False
    
    def change_message_visibility(self, receipt_handle: str, timeout: int) -> bool:
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
            return True
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e}")
            return False
    
    def send_to_dlq(self, message: Dict[str, Any], dlq_url: str):
        try:
            self.sqs_client.send_message(
                QueueUrl=dlq_url,
                MessageBody=json.dumps({
                    'original_message': message,
                    'failed_at': datetime.utcnow().isoformat(),
                    'reason': 'Processing failed'
                })
            )
            logger.info(f"Sent message to DLQ: {message['message_id']}")
        except ClientError as e:
            logger.error(f"Error sending to DLQ: {e}")
    
    def process_batch(self, delete_on_success: bool = True, dlq_url: Optional[str] = None):
        messages = self.poll_messages()
        
        if not messages:
            logger.debug("No messages received")
            return
        
        logger.info(f"Received {len(messages)} messages")
        
        for message in messages:
            parsed_message = self.parse_message(message)
            success = self.process_message(parsed_message)
            
            if success and delete_on_success:
                self.delete_message(parsed_message['receipt_handle'])
            elif not success and dlq_url:
                self.send_to_dlq(parsed_message, dlq_url)
                self.delete_message(parsed_message['receipt_handle'])
    
    def start(
        self,
        delete_on_success: bool = True,
        dlq_url: Optional[str] = None,
        poll_interval: int = 0
    ):
        self.running = True
        logger.info("Starting SQS worker...")
        
        while self.running:
            try:
                self.process_batch(delete_on_success, dlq_url)
                if poll_interval > 0:
                    time.sleep(poll_interval)
            except KeyboardInterrupt:
                logger.info("Received shutdown signal")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {e}")
                time.sleep(5)
    
    def stop(self):
        self.running = False
        logger.info("Stopping SQS worker...")


